cssVars:
:root {
  --color-primary: #C9A84C;
  --color-primary-hover: #B8973F;
  --color-secondary: #8B7355;
  --color-surface: #1A1A1A;
  --color-background: #0D0D0D;
  --color-card: #1A1A1A;
  --color-text: #F5F0E8;
  --color-text-muted: #8B7355;
  --color-border: #2D2D2D;
  --color-error: #C0392B;
  --color-success: #27AE60;
  --color-warning: #C9A84C;
  --color-info: #2980B9;
  --font-heading: Playfair Display, Georgia, serif;
  --font-body: Cormorant Garamond, Georgia, serif;
  --font-mono: JetBrains Mono, monospace;
  --radius-sm: 1px;
  --radius-md: 2px;
  --radius-lg: 4px;
  --radius-xl: 8px;
  --radius-full: 9999px;
  --shadow-sm: 0 1px 4px rgba(201,168,76,0.1);
  --shadow-md: 0 4px 16px rgba(201,168,76,0.15);
  --shadow-lg: 0 8px 32px rgba(201,168,76,0.2);
  --shadow-xl: 0 16px 64px rgba(201,168,76,0.25);
}
